import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";


const FAQS = [
  { q: "How do I calculate mileage reimbursement?", a: "Multiply your total business miles driven by the applicable IRS standard mileage rate. For 2024, the IRS rate is 67 cents per mile for business travel. Example: 500 miles  x  $0.67 = $335 reimbursement. You can claim this rate instead of tracking actual expenses like gas, insurance, and maintenance." },
  { q: "What is the IRS standard mileage rate for 2024?", a: "The 2024 IRS standard mileage rates are: 67 cents per mile for business use (up from 65.5- cents in 2023), 21 cents per mile for medical or moving purposes, and 14 cents per mile for charitable service. The business rate is updated annually and sometimes mid-year during high fuel price periods." },
  { q: "How do I track mileage for taxes?", a: "Keep a contemporaneous mileage log recording: date, starting location, destination, business purpose, and miles driven for each trip. IRS requires written records to support deductions - apps like MileIQ, Everlance, or TripLog automate this via GPS tracking. Manual spreadsheets work too. The IRS recommends recording trips the same day they occur." },
  { q: "Can I deduct car expenses instead of mileage?", a: "Yes - you can choose either the standard mileage rate or the actual expense method (gas, oil, tires, repairs, insurance, registration, depreciation/lease payments). You must choose in the first year you use the car for business, though there are some exceptions. Actual expenses often yield higher deductions for expensive, gas-inefficient vehicles." },
  { q: "Is the mileage reimbursement rate taxable?", a: "Reimbursements at or below the IRS standard rate are not taxable income to employees when paid under an accountable plan (proper documentation required). Amounts above the IRS rate are taxable to the employee. If your employer doesn't reimburse you, you may deduct business mileage on Schedule C (self-employed) or as a W-2 employee in some states." },
  { q: "What if my employer reimburses less than the IRS rate?", a: "If reimbursed below the IRS rate, the difference may be deductible as unreimbursed employee expenses on your state return (federal deduction was eliminated post-2017 for employees). Self-employed workers can always deduct the full IRS rate on Schedule C regardless of partial reimbursements received." },
  { q: "How do I calculate actual driving cost vs. IRS reimbursement?", a: "Calculate: Gallons used = Miles  x  MPG; Fuel cost = Gallons  x  Gas price. This is just fuel cost - actual total cost also includes insurance, maintenance (~$0.08-0.12/mile), and depreciation (~$0.10-0.25/mile for newer cars). The IRS rate is designed to cover all these costs combined." },
  { q: "What is the IRS mileage rate history?", a: "The IRS rate has risen significantly: 2020: 57.5- cents, 2021: 56- cents, 2022: 58.5- cents (raised to 62.5- cents mid-year), 2023: 65.5- cents, 2024: 67- cents. The rate reflects an average of gas prices, vehicle depreciation, insurance, and maintenance costs across a fleet of vehicles. It's adjusted annually (and sometimes mid-year) based on fuel cost changes." },
];

const IRS_RATES = [
  ["2020", "$0.575/mile", "COVID-era rate reduction"],
  ["2021", "$0.560/mile", "Lowest rate in years"],
  ["2022 (Jan-Jun)", "$0.585/mile", "Standard rate"],
  ["2022 (Jul-Dec)", "$0.625/mile", "Mid-year increase due to fuel prices"],
  ["2023", "$0.655/mile", "Standard rate"],
  ["2024", "$0.670/mile", "Current rate"],
];

export default function MileageCalculator() {
  useCurrencyVersion();
  const [miles, setMiles] = useState(500);
  const [rate, setRate] = useState(0.67);
  const [mpg, setMpg] = useState(30);
  const [gasPrice, setGasPrice] = useState(3.50);

  const reimbursement = miles * rate;
  const gallons = miles / mpg;
  const fuelCost = gallons * gasPrice;
  const profit = reimbursement - fuelCost;

  const fmt = (n: number) => formatCurrencyValue(n, { minimumFractionDigits: 2 });

  const milesRows = [100, 250, 500, 1000, 2500, 5000, 10000];

  return (
    <>
      <SEOHead
        title="Free Mileage Reimbursement Calculator Online - Calculate IRS Mileage Rate Instantly | CalcHive"
        description="Free online mileage reimbursement calculator. Calculate mileage reimbursement using the IRS standard rate and compare to actual fuel cost instantly. 100% free for employees and businesses, no signup required."
        canonical="/mileage-calculator"
        keywords="free mileage reimbursement calculator, IRS mileage rate calculator free online, business mileage calculator free, calculate mileage reimbursement free, IRS standard mileage calculator free"
        category="Automotive Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-rose-600 dark:text-rose-400 bg-rose-50 dark:bg-rose-950/50 px-3 py-1 rounded-full mb-4 inline-block">Transportation</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Mileage Reimbursement Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free mileage reimbursement calculator to calculate mileage reimbursement free using the IRS standard rate and compare it to actual fuel cost. This IRS mileage rate calculator free online also works as a business mileage calculator free and IRS standard mileage calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="miles" label="Miles Driven" value={miles} min={1} max={10000} step={1} onChange={setMiles} format={v => `${v.toLocaleString()} miles`} testId="input-miles" />
            <SliderInput id="rate" label="Reimbursement Rate" value={rate} min={0.10} max={1.00} step={0.01} onChange={setRate} format={v => `${fmt(v)}/mile`} testId="input-rate" helpText={`2024 IRS business rate: ${fmt(0.67)}/mile`} />
            <SliderInput id="mpg" label="Your Car's Fuel Economy" value={mpg} min={5} max={150} step={0.5} onChange={setMpg} format={v => `${v} MPG`} testId="input-mpg" />
            <SliderInput id="gas" label="Gas Price" value={gasPrice} min={1} max={8} step={0.01} onChange={setGasPrice} format={v => `${fmt(v)}/gal`} testId="input-gas" />
          </div>
          <motion.div key={`${miles}-${rate}-${mpg}-${gasPrice}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-rose-500 to-rose-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Total Reimbursement</p>
              <p className="text-5xl font-black text-white tracking-tight" data-testid="result-reimbursement">{fmt(reimbursement)}</p>
              <p className="text-white/70 text-sm mt-1">{miles.toLocaleString()} miles  x  {fmt(rate)}/mile</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Actual Fuel Cost", value: fmt(fuelCost) },
                { label: "Your Profit", value: fmt(profit), green: profit > 0, red: profit < 0 },
                { label: "Gallons Used", value: `${gallons.toFixed(2)} gal` },
              ].map(({ label, value, green, red }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className={`text-base font-extrabold ${green ? "text-emerald-600 dark:text-emerald-400" : red ? "text-red-600 dark:text-red-400" : "text-foreground"}`}>{value}</p>
                </div>
              ))}
            </div>
            <p className="text-xs text-muted-foreground mt-3 text-center">Note: actual driving costs include maintenance, insurance, and depreciation beyond just fuel.</p>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Mileage Reimbursement Using the IRS Rate for Free</h2>
          <p className="text-muted-foreground leading-relaxed">The IRS standard mileage rate is set annually to cover the average cost of operating a vehicle for business purposes - including fuel, maintenance, insurance, registration, and depreciation. Using this rate instead of tracking actual expenses greatly simplifies tax record-keeping.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Reimbursement = Miles  x  IRS Rate</p>
            <p>Fuel Cost = (Miles  x  MPG)  x  Gas Price</p>
            <p>Profit = Reimbursement - Fuel Cost</p>
            <p className="text-xs text-muted-foreground mt-2">2024 IRS business rate: $0.67/mile - Medical/moving: $0.21/mile - Charity: $0.14/mile</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">IRS Standard Mileage Rate vs Actual Fuel Cost Compared</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Miles", "Reimbursement ($0.67)", "Fuel Cost (30 MPG @ $3.50)", "Profit"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {milesRows.map(m => {
                  const r = m * 0.67;
                  const f = (m / 30) * 3.50;
                  const p = r - f;
                  return (
                    <tr key={m} className={`hover:bg-muted/30 ${m === miles ? "bg-rose-50 dark:bg-rose-950/20 font-semibold" : ""}`}>
                      <td className="py-2.5 px-4 font-semibold text-foreground">{m.toLocaleString()} mi{m === miles ? " (current)" : ""}</td>
                      <td className="py-2.5 px-4 text-rose-600 dark:text-rose-400 font-bold">{fmt(r)}</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{fmt(f)}</td>
                      <td className="py-2.5 px-4 text-emerald-600 dark:text-emerald-400 font-medium">{fmt(p)}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Business Mileage Calculator for Employees and Employers</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Year", "Business Rate", "Notes"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {IRS_RATES.map(([year, rate_, notes]) => (
                  <tr key={year} className={`hover:bg-muted/30 ${year === "2024" ? "bg-rose-50 dark:bg-rose-950/20 font-semibold" : ""}`}>
                    <td className="py-2.5 px-4 font-bold text-foreground">{year}</td>
                    <td className="py-2.5 px-4 text-rose-600 dark:text-rose-400 font-bold">{rate_}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{notes}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/mileage-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


